    void process_hitscan(Player& shooter, const Vec3& origin, const Vec3& direction) {
        float closest_dist = WEAPON_RANGE;
        Player* hit_player = nullptr;

        constexpr float PLAYER_HITBOX_RADIUS = 1.0f;

        for (auto& [id, target] : players) {
            if (id == shooter.id || !target.alive) continue;

            // Ray-sphere intersection for hit detection
            Vec3 to_target = target.position - origin;
            float proj = to_target.dot(direction);

            if (proj < 0 || proj > WEAPON_RANGE) continue;

            Vec3 closest_point(
                origin.x + direction.x * proj,
                origin.y + direction.y * proj,
                origin.z + direction.z * proj
            );

            Vec3 diff = closest_point - target.position;
            float dist_sq = diff.x * diff.x + diff.y * diff.y + diff.z * diff.z;

            if (dist_sq <= PLAYER_HITBOX_RADIUS * PLAYER_HITBOX_RADIUS) {
                if (proj < closest_dist) {
                    closest_dist = proj;
                    hit_player = &target;
                }
            }
        }

        if (hit_player) {
            hit_player->health -= WEAPON_DAMAGE;

            std::cout << "[GAME] Player " << shooter.id << " hit player "
                      << hit_player->id << " for " << WEAPON_DAMAGE
                      << " damage (health: " << hit_player->health << ")" << std::endl;

            // Send hit notification
            struct HitNotification {
                uint32_t shooter_id;
                uint32_t target_id;
                int32_t damage;
                int32_t remaining_health;
            } hit_notify;

            hit_notify.shooter_id = shooter.id;
            hit_notify.target_id = hit_player->id;
            hit_notify.damage = WEAPON_DAMAGE;
            hit_notify.remaining_health = hit_player->health;

            broadcast_to_all(PacketType::PLAYER_HIT,
                           reinterpret_cast<const uint8_t*>(&hit_notify),
                           sizeof(hit_notify));

            if (hit_player->health <= 0) {
                hit_player->health = 0;
                hit_player->alive = false;

                std::cout << "[GAME] Player " << hit_player->id
                          << " killed by player " << shooter.id << std::endl;

                struct DeathNotification {
                    uint32_t killed_id;
                    uint32_t killer_id;
                } death_notify;

                death_notify.killed_id = hit_player->id;
                death_notify.killer_id = shooter.id;

                broadcast_to_all(PacketType::PLAYER_DEATH,
                               reinterpret_cast<const uint8_t*>(&death_notify),
                               sizeof(death_notify));
            }
        }
    }

    void handle_heartbeat(Player& player, const uint8_t* payload, size_t len) {
        if (len < sizeof(HeartbeatPayload)) return;

        HeartbeatPayload hb;
        std::memcpy(&hb, payload, sizeof(HeartbeatPayload));

        if (hb.player_id != player.id) return;

        player.last_heartbeat = std::chrono::steady_clock::now();

        // Echo heartbeat back
        send_packet(player.address, player.session_key,
                   PacketType::HEARTBEAT,
                   reinterpret_cast<const uint8_t*>(&hb), sizeof(hb));
    }

    void handle_disconnect(Player& player) {
        std::string key = addr_key(player.address);
        std::cout << "[INFO] Player " << player.id << " disconnected" << std::endl;

        struct DisconnectNotify {
            uint32_t player_id;
        } notify;
        notify.player_id = player.id;

        // Notify others before removing
        for (auto& [id, other] : players) {
            if (id != player.id && other.authenticated) {
                send_packet(other.address, other.session_key,
                           PacketType::PLAYER_DISCONNECT,
                           reinterpret_cast<const uint8_t*>(&notify), sizeof(notify));
            }
        }

        address_to_player.erase(key);
        players.erase(player.id);
    }

    void broadcast_to_all(PacketType type, const uint8_t* payload, size_t payload_len) {
        for (auto& [id, player] : players) {
            if (player.authenticated) {
                send_packet(player.address, player.session_key,
                           type, payload, payload_len);
            }
        }
    }

